+) -> Result<usize, FaultInjectionError> {
+    match params.get(key) {
+        Some(_) => param_usize(params, scenario, variant, key),
+        None => Ok(default),
+    }
+}
+
+fn param_u8_with_default(
+    params: &Value,
+    scenario: &FaultScenario,
+    variant: &FaultVariant,
+    key: &str,
