+    #[must_use]
+    pub fn to_alert_rules_yaml(&self) -> String {
+        #[derive(Serialize)]
+        struct RuleLabels<'a> {
+            severity: &'a str,
+        }
+
+        #[derive(Serialize)]
+        struct RuleAnnotations<'a> {
+            summary: &'a str,
+        }
+
+        #[derive(Serialize)]
+        struct Rule<'a> {
+            alert: &'a str,
+            expr: &'a str,
+            #[serde(rename = "for")]
+            for_window: &'a str,
+            labels: RuleLabels<'a>,
+            annotations: RuleAnnotations<'a>,
+        }
+
+        #[derive(Serialize)]
+        struct RuleGroup<'a> {
+            name: &'a str,
+            rules: Vec<Rule<'a>>,
+        }
+
+        #[derive(Serialize)]
+        struct RuleFile<'a> {
+            groups: Vec<RuleGroup<'a>>,
+        }
+
+        let rules = self
+            .alert_rules
+            .iter()
+            .map(|rule| Rule {
+                alert: rule.alert.as_str(),
+                expr: rule.expr.as_str(),
+                for_window: rule.for_window.as_str(),
+                labels: RuleLabels {
+                    severity: rule.severity.as_str(),
+                },
+                annotations: RuleAnnotations {
+                    summary: rule.summary.as_str(),
+                },
+            })
+            .collect();
+        serde_yaml::to_string(&RuleFile {
+            groups: vec![RuleGroup {
+                name: "frankenlibc-observability",
+                rules,
+            }],
+        })
+        .unwrap_or_else(|err| format!("error: {err}\n"))
+    }
