+        "id": id,
+        "type": "stat",
+        "title": title,
+        "datasource": {"type": "prometheus", "uid": "prometheus"},
+        "gridPos": {"h": 8, "w": 8, "x": ((id - 1) % 3) * 8, "y": row * 8},
+        "targets": [{"refId": "A", "expr": expr}],
+        "fieldConfig": {"defaults": {"unit": unit}}
+    })
+}
