+        "gridPos": {"h": 9, "w": 12, "x": if id.is_multiple_of(2) { 12 } else { 0 }, "y": 8 + (((id - 4) / 2) * 9)},
+        "targets": [{"refId": "A", "expr": expr}],
+        "fieldConfig": {"defaults": {"unit": "short"}}
+    })
+}
